# Generated by anthropic (claude-opus-4-6)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security


pipeline {
    agent any

    parameters {
        string(
            name: 'ARTIFACT_URLS',
            defaultValue: '',
            description: 'Comma-separated list of artifact URLs to download (supports S3, Artifactory, HTTP/HTTPS)'
        )
        string(
            name: 'DEPLOY_SERVERS',
            defaultValue: '',
            description: 'Comma-separated list of production server hostnames/IPs to deploy to'
        )
        string(
            name: 'DEPLOY_PATH',
            defaultValue: '/opt/app/deploy',
            description: 'Target deployment directory on production servers'
        )
        string(
            name: 'DEPLOY_USER',
            defaultValue: 'deploy',
            description: 'SSH user for deployment to production servers'
        )
        credentials(
            name: 'SSH_CREDENTIALS_ID',
            defaultValue: '',
            description: 'SSH credentials for connecting to production servers',
            credentialType: 'com.cloudbees.jenkins.plugins.sshcredentials.impl.BasicSSHUserPrivateKey'
        )
        credentials(
            name: 'ARTIFACTORY_CREDENTIALS_ID',
            defaultValue: '',
            description: 'Credentials for Artifactory authentication (optional)',
            credentialType: 'com.cloudbees.plugins.credentials.impl.UsernamePasswordCredentialsImpl'
        )
        credentials(
            name: 'AWS_CREDENTIALS_ID',
            defaultValue: '',
            description: 'AWS credentials for S3 access (optional)',
            credentialType: 'com.cloudbees.jenkins.plugins.awscredentials.AWSCredentialsImpl'
        )
        string(
            name: 'PRE_DEPLOY_SCRIPT',
            defaultValue: '',
            description: 'Optional script to run on each server before deployment (e.g., stop services)'
        )
        string(
            name: 'POST_DEPLOY_SCRIPT',
            defaultValue: '',
            description: 'Optional script to run on each server after deployment (e.g., start services)'
        )
        string(
            name: 'HEALTH_CHECK_URL_PATTERN',
            defaultValue: '',
            description: 'Health check URL pattern (use {SERVER} as placeholder, e.g., http://{SERVER}:8080/health)'
        )
        string(
            name: 'HEALTH_CHECK_TIMEOUT',
            defaultValue: '120',
            description: 'Health check timeout in seconds'
        )
        booleanParam(
            name: 'ROLLING_DEPLOY',
            defaultValue: true,
            description: 'Deploy to servers one at a time (rolling) vs all at once'
        )
        booleanParam(
            name: 'BACKUP_EXISTING',
            defaultValue: true,
            description: 'Backup existing artifacts before deployment'
        )
        booleanParam(
            name: 'DRY_RUN',
            defaultValue: false,
            description: 'Perform a dry run without actual deployment'
        )
    }

    environment {
        ARTIFACTS_DIR = "${WORKSPACE}/artifacts"
        CHECKSUM_FILE = "${WORKSPACE}/artifacts/checksums.sha256"
        DEPLOY_TIMESTAMP = sh(script: 'date +%Y%m%d_%H%M%S', returnStdout: true).trim()
    }

    options {
        timeout(time: 60, unit: 'MINUTES')
        timestamps()
        buildDiscarder(logRotator(numToKeepStr: '30'))
        disableConcurrentBuilds()
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    echo "=== Validating Pipeline Parameters ==="

                    if (!params.ARTIFACT_URLS?.trim()) {
                        error "ARTIFACT_URLS parameter is required. Provide comma-separated URLs."
                    }
                    if (!params.DEPLOY_SERVERS?.trim()) {
                        error "DEPLOY_SERVERS parameter is required. Provide comma-separated server addresses."
                    }
                    if (!params.SSH_CREDENTIALS_ID?.trim()) {
                        error "SSH_CREDENTIALS_ID is required for deployment."
                    }

                    env.ARTIFACT_URL_LIST = params.ARTIFACT_URLS.trim()
                    env.SERVER_LIST = params.DEPLOY_SERVERS.trim()

                    def urls = env.ARTIFACT_URL_LIST.split(',').collect { it.trim() }.findAll { it }
                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }

                    echo "Artifacts to download (${urls.size()}):"
                    urls.eachWithIndex { url, idx ->
                        echo "  ${idx + 1}. ${url}"
                    }

                    echo "Target servers (${servers.size()}):"
                    servers.eachWithIndex { server, idx ->
                        echo "  ${idx + 1}. ${server}"
                    }

                    echo "Deploy path: ${params.DEPLOY_PATH}"
                    echo "Rolling deploy: ${params.ROLLING_DEPLOY}"
                    echo "Backup existing: ${params.BACKUP_EXISTING}"
                    echo "Dry run: ${params.DRY_RUN}"

                    if (params.DRY_RUN) {
                        echo "*** DRY RUN MODE - No actual deployment will occur ***"
                    }

                    // Validate URL formats
                    urls.each { url ->
                        if (!url.matches('^(https?://|s3://).*')) {
                            error "Invalid URL format: ${url}. Supported protocols: http, https, s3"
                        }
                    }
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                script {
                    echo "=== Preparing Workspace ==="
                    sh """
                        rm -rf ${ARTIFACTS_DIR}
                        mkdir -p ${ARTIFACTS_DIR}
                    """
                }
            }
        }

        stage('Download Artifacts') {
            steps {
                script {
                    echo "=== Downloading Artifacts ==="

                    def urls = env.ARTIFACT_URL_LIST.split(',').collect { it.trim() }.findAll { it }
                    def downloadResults = [:]

                    urls.each { url ->
                        def filename = extractFilename(url)
                        def targetPath = "${ARTIFACTS_DIR}/${filename}"

                        echo "Downloading: ${url}"
                        echo "  -> ${targetPath}"

                        try {
                            if (url.startsWith('s3://')) {
                                downloadFromS3(url, targetPath)
                            } else if (url.contains('artifactory') || url.contains('jfrog')) {
                                downloadFromArtifactory(url, targetPath)
                            } else {
                                downloadFromHttp(url, targetPath)
                            }

                            // Verify download
                            def fileSize = sh(
                                script: "stat -c%s '${targetPath}' 2>/dev/null || stat -f%z '${targetPath}' 2>/dev/null",
                                returnStdout: true
                            ).trim()

                            if (fileSize == '0') {
                                error "Downloaded file is empty: ${filename}"
                            }

                            echo "  Downloaded successfully (${formatFileSize(fileSize.toLong())})"
                            downloadResults[filename] = [url: url, size: fileSize, status: 'SUCCESS']

                        } catch (Exception e) {
                            downloadResults[filename] = [url: url, status: 'FAILED', error: e.message]
                            error "Failed to download ${url}: ${e.message}"
                        }
                    }

                    // Generate checksums
                    sh """
                        cd ${ARTIFACTS_DIR}
                        sha256sum * > checksums.sha256 2>/dev/null || shasum -a 256 * > checksums.sha256
                    """

                    echo "\n=== Download Summary ==="
                    echo sh(script: "cat ${CHECKSUM_FILE}", returnStdout: true)

                    // Store results for later stages
                    env.DOWNLOAD_RESULTS = downloadResults.collect { k, v -> "${k}:${v.status}" }.join(',')
                }
            }
        }

        stage('Verify Artifacts') {
            steps {
                script {
                    echo "=== Verifying Downloaded Artifacts ==="

                    def artifacts = sh(
                        script: "ls -1 ${ARTIFACTS_DIR}/ | grep -v checksums.sha256",
                        returnStdout: true
                    ).trim().split('\n').findAll { it }

                    if (artifacts.size() == 0) {
                        error "No artifacts found in download directory"
                    }

                    artifacts.each { artifact ->
                        def filePath = "${ARTIFACTS_DIR}/${artifact}"
                        echo "Verifying: ${artifact}"

                        // Check file exists and is not empty
                        sh "test -s '${filePath}' || (echo 'File is empty or missing: ${artifact}' && exit 1)"

                        // Check if archive and validate integrity
                        if (artifact.endsWith('.tar.gz') || artifact.endsWith('.tgz')) {
                            sh "gzip -t '${filePath}'"
                            echo "  ✓ Valid gzip archive"
                        } else if (artifact.endsWith('.zip')) {
                            sh "unzip -t '${filePath}' > /dev/null"
                            echo "  ✓ Valid zip archive"
                        } else if (artifact.endsWith('.jar') || artifact.endsWith('.war') || artifact.endsWith('.ear')) {
                            sh "unzip -t '${filePath}' > /dev/null"
                            echo "  ✓ Valid Java archive"
                        } else {
                            echo "  ✓ File exists (no specific integrity check for this type)"
                        }
                    }

                    echo "\nAll artifacts verified successfully."
                }
            }
        }

        stage('Approval') {
            when {
                expression { return !params.DRY_RUN }
            }
            steps {
                script {
                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }
                    def artifacts = sh(
                        script: "ls -1 ${ARTIFACTS_DIR}/ | grep -v checksums.sha256",
                        returnStdout: true
                    ).trim()

                    def approvalMessage = """
                    |=== Deployment Approval Required ===
                    |
                    |Artifacts to deploy:
                    |${artifacts}
                    |
                    |Target servers: ${servers.join(', ')}
                    |Deploy path: ${params.DEPLOY_PATH}
                    |Rolling deploy: ${params.ROLLING_DEPLOY}
                    |
                    |Proceed with deployment?
                    """.stripMargin()

                    timeout(time: 30, unit: 'MINUTES') {
                        input(
                            message: approvalMessage,
                            ok: 'Deploy to Production',
                            submitter: 'admin,deployers'
                        )
                    }
                }
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }
                    def deployResults = [:]

                    if (params.DRY_RUN) {
                        echo "*** DRY RUN - Simulating deployment ***"
                        servers.each { server ->
                            echo "Would deploy to: ${server}:${params.DEPLOY_PATH}"
                        }
                        return
                    }

                    if (params.ROLLING_DEPLOY) {
                        echo "=== Starting Rolling Deployment ==="
                        servers.each { server ->
                            echo "\n--- Deploying to ${server} ---"
                            try {
                                deployToServer(server)
                                deployResults[server] = 'SUCCESS'
                                echo "✓ Deployment to ${server} completed successfully"
                            } catch (Exception e) {
                                deployResults[server] = 'FAILED'
                                echo "✗ Deployment to ${server} failed: ${e.message}"
                                error "Rolling deployment halted due to failure on ${server}"
                            }
                        }
                    } else {
                        echo "=== Starting Parallel Deployment ==="
                        def parallelStages = [:]
                        servers.each { server ->
                            def serverName = server
                            parallelStages["Deploy to ${serverName}"] = {
                                try {
                                    deployToServer(serverName)
                                    deployResults[serverName] = 'SUCCESS'
                                    echo "✓ Deployment to ${serverName} completed successfully"
                                } catch (Exception e) {
                                    deployResults[serverName] = 'FAILED'
                                    echo "✗ Deployment to ${serverName} failed: ${e.message}"
                                    throw e
                                }
                            }
                        }
                        parallel parallelStages
                    }

                    echo "\n=== Deployment Summary ==="
                    deployResults.each { server, status ->
                        echo "  ${server}: ${status}"
                    }
                }
            }
        }

        stage('Health Checks') {
            when {
                expression { return params.HEALTH_CHECK_URL_PATTERN?.trim() && !params.DRY_RUN }
            }
            steps {
                script {
                    echo "=== Running Health Checks ==="

                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }
                    def timeout = params.HEALTH_CHECK_TIMEOUT.toInteger()
                    def healthResults = [:]

                    servers.each { server ->
                        def healthUrl = params.HEALTH_CHECK_URL_PATTERN.replace('{SERVER}', server)
                        echo "Checking health: ${healthUrl}"

                        try {
                            def healthy = performHealthCheck(healthUrl, timeout)
                            healthResults[server] = healthy ? 'HEALTHY' : 'UNHEALTHY'
                            if (!healthy) {
                                echo "WARNING: ${server} did not pass health check within ${timeout}s"
                            } else {
                                echo "✓ ${server} is healthy"
                            }
                        } catch (Exception e) {
                            healthResults[server] = 'ERROR'
                            echo "ERROR: Health check failed for ${server}: ${e.message}"
                        }
                    }

                    echo "\n=== Health Check Summary ==="
                    healthResults.each { server, status ->
                        echo "  ${server}: ${status}"
                    }

                    def unhealthyServers = healthResults.findAll { it.value != 'HEALTHY' }
                    if (unhealthyServers) {
                        unstable "Some servers are not healthy: ${unhealthyServers.keySet().join(', ')}"
                    }
                }
            }
        }

        stage('Smoke Tests') {
            when {
                expression { return !params.DRY_RUN }
            }
            steps {
                script {
                    echo "=== Running Smoke Tests ==="

                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }

                    sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
                        servers.each { server ->
                            echo "Smoke testing ${server}..."

                            // Verify artifacts exist on target
                            def artifacts = sh(
                                script: "ls -1 ${ARTIFACTS_DIR}/ | grep -v checksums.sha256",
                                returnStdout: true
                            ).trim().split('\n').findAll { it }

                            artifacts.each { artifact ->
                                def remoteFile = "${params.DEPLOY_PATH}/${artifact}"
                                def exists = sh(
                                    script: "ssh -o StrictHostKeyChecking=no ${params.DEPLOY_USER}@${server} 'test -f ${remoteFile} && echo exists || echo missing'",
                                    returnStdout: true